import React, { useState, useEffect } from "react";
import { 
  Users, Stethoscope, Calendar, CreditCard, Menu, 
  LogOut, Shield, HeartPulse, Activity, UserPlus, FileText, Pill
} from "lucide-react";
import "./index.css";

const API_BASE = "http://127.0.0.1:5000";

function App() {
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [loading, setLoading] = useState(false);

  const [patients, setPatients] = useState([]);
  const [loginForm, setLoginForm] = useState({ username: "", password: "" });
  const [patientForm, setPatientForm] = useState({ name: "", age: "", gender: "Male" });

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await fetch(`${API_BASE}/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(loginForm)
      });
      const data = await res.json();
      if (res.ok) {
        setUser({ ...data, username: loginForm.username });
        setActiveTab("dashboard");
      } else {
        alert("ACCESS DENIED");
      }
    } catch (err) {
      console.error(err);
      alert("CONNECTION ERROR");
    }
    setLoading(false);
  };

  const logout = () => {
    setUser(null);
    setLoginForm({ username: "", password: "" });
  };

  const getCommonHeaders = () => ({
    "Content-Type": "application/json",
    "role": user?.role || "",
    "user_id": user?.user_id || ""
  });

  const fetchPatients = async () => {
    try {
      const res = await fetch(`${API_BASE}/test-db`);
      const data = await res.json();
      setPatients(data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => {
    if (user) fetchPatients();
  }, [user]);

  const addPatient = async (e) => {
    e.preventDefault();
    try {
      await fetch(`${API_BASE}/test-add`, {
        method: "POST",
        headers: getCommonHeaders(),
        body: JSON.stringify(patientForm)
      });
      alert("PATIENT REGISTERED");
      setPatientForm({ name: "", age: "", gender: "Male" });
      fetchPatients();
    } catch (err) { alert("REGISTRATION FAILED"); }
  };

  if (!user) {
    return (
      <div className="login-screen">
        <div className="login-card">
          <div className="login-card-header">
            <HeartPulse size={48} color="var(--text-primary)" strokeWidth={3} />
            <h2>MediCore</h2>
            <p>SYSTEM AUTHENTICATION REQUIRED</p>
          </div>
          <form onSubmit={handleLogin}>
            <div className="input-group">
              <label>Identifier</label>
              <input 
                type="text" 
                placeholder="USERNAME"
                value={loginForm.username}
                onChange={(e) => setLoginForm({ ...loginForm, username: e.target.value })}
                required
              />
            </div>
            <div className="input-group">
              <label>Passcode</label>
              <input 
                type="password" 
                placeholder="PASSWORD"
                value={loginForm.password}
                onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}
                required
              />
            </div>
            <button className="btn" type="submit" style={{ width: "100%", marginTop: 16 }} disabled={loading}>
              {loading ? "VERIFYING..." : "ENTER SYSTEM"} <LogOut size={18} />
            </button>
          </form>
          <div style={{ textAlign: "center", marginTop: 32 }}>
             <p style={{ fontSize: "0.80rem", fontWeight: 600, color: "var(--text-secondary)" }}>DEFAULT: Admin@123 / Doctor@123 / Staff@123 / Patient@123</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="app-container">
      {/* Sidebar Navigation */}
      <aside className="sidebar">
        <div className="brand">
          <HeartPulse size={28} color="var(--text-primary)" strokeWidth={3} />
          MediCore
        </div>

        <nav className="nav-links">
          <button 
            className={`nav-item ${activeTab === "dashboard" ? "active" : ""}`}
            onClick={() => setActiveTab("dashboard")}
          >
            <Activity size={20} /> Dashboard
          </button>
          <button 
            className={`nav-item ${activeTab === "patients" ? "active" : ""}`}
            onClick={() => setActiveTab("patients")}
          >
            <Users size={20} /> Patients
          </button>
          {(user.role === "admin" || user.role === "staff") && (
            <button 
              className={`nav-item ${activeTab === "doctors" ? "active" : ""}`}
              onClick={() => setActiveTab("doctors")}
            >
              <Stethoscope size={20} /> Doctors
            </button>
          )}
          <button 
            className={`nav-item ${activeTab === "appointments" ? "active" : ""}`}
            onClick={() => setActiveTab("appointments")}
          >
            <Calendar size={20} /> Appointments
          </button>
          <button 
            className={`nav-item ${activeTab === "billing" ? "active" : ""}`}
            onClick={() => setActiveTab("billing")}
          >
            <CreditCard size={20} /> Billing
          </button>
        </nav>

        <div style={{ marginTop: "auto", borderTop: "2px solid var(--border-color)", paddingTop: 24 }}>
          <button className="btn btn-outline" onClick={logout} style={{ width: "100%" }}>
            <LogOut size={18} /> SIGN OUT
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="main-content">
        <header className="header">
          <div>
            <h1>PORTAL OVERVIEW</h1>
            <p>ACTIVE SESSION: {user.username.toUpperCase()}</p>
          </div>
          <div className="user-profile">
             <div className="user-info">
                <strong>{user.username}</strong>
                <p className="role-badge">ROLE: {user.role}</p>
             </div>
             <div className="avatar">
               {user.username.charAt(0).toUpperCase()}
             </div>
          </div>
        </header>

        {activeTab === "dashboard" && (
          <div>
            <div className="grid-cards">
              <div className="solid-card">
                <div className="card-icon"><Users size={28} strokeWidth={3} /></div>
                <div className="stat-value">{patients.length || 0}</div>
                <div className="stat-label">TOTAL PATIENTS</div>
              </div>
              <div className="solid-card">
                <div className="card-icon"><Calendar size={28} strokeWidth={3} /></div>
                <div className="stat-value">12</div>
                <div className="stat-label">SCHEDULED VISITS</div>
              </div>
              <div className="solid-card">
                <div className="card-icon"><Shield size={28} strokeWidth={3} /></div>
                <div className="stat-value">ON</div>
                <div className="stat-label">SYSTEM STATE</div>
              </div>
            </div>

            <div className="form-container">
              <div className="solid-card">
                <h3 className="form-header">
                  <UserPlus size={24} strokeWidth={3} /> QUICK REGISTER
                </h3>
                <form onSubmit={addPatient}>
                  <div className="input-group">
                    <label>FULL NAME</label>
                    <input 
                      type="text" 
                      placeholder="ENTER NAME"
                      value={patientForm.name} 
                      onChange={(e) => setPatientForm({...patientForm, name: e.target.value})}
                      required 
                    />
                  </div>
                  <div className="input-group">
                    <label>AGE</label>
                    <input 
                      type="number" 
                      placeholder="ENTER AGE"
                      value={patientForm.age} 
                      onChange={(e) => setPatientForm({...patientForm, age: e.target.value})}
                      required 
                    />
                  </div>
                  <div className="input-group">
                    <label>IDENTIFIED GENDER</label>
                    <select 
                      value={patientForm.gender}
                      onChange={(e) => setPatientForm({...patientForm, gender: e.target.value})}
                    >
                      <option>Male</option>
                      <option>Female</option>
                      <option>Other</option>
                    </select>
                  </div>
                  <button type="submit" className="btn" style={{ marginTop: 12 }}>ADD RECORD</button>
                </form>
              </div>

              <div className="solid-card">
                <h3 className="form-header">
                  <FileText size={24} strokeWidth={3} /> RECENT ENTRIES
                </h3>
                <div style={{ display: "flex", flexDirection: "column" }}>
                  {patients.slice(-5).reverse().map(p => (
                    <div key={p.patient_id} className="list-item">
                      <div>
                        <strong style={{ fontSize: "1.1rem", textTransform: "uppercase" }}>{p.name}</strong>
                        <div style={{ fontSize: "0.85rem", color: "var(--text-secondary)", marginTop: 4, fontWeight: 600 }}>AGE: {p.age} // {p.gender.toUpperCase()}</div>
                      </div>
                      <div className="status-badge">PID-{p.patient_id}</div>
                    </div>
                  ))}
                  {patients.length === 0 && <p className="empty-state">NO RECORDS FOUND IN DATABASE.</p>}
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === "patients" && (
           <div className="solid-card">
             <h2 className="form-header">PATIENT DIRECTORY</h2>
             <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "24px" }}>
                {patients.map(p => (
                   <div key={p.patient_id} className="list-item" style={{ margin: 0 }}>
                      <div>
                         <strong style={{ fontSize: "1.2rem", textTransform: "uppercase" }}>{p.name}</strong>
                         <p style={{ marginTop: "4px", color: "var(--text-secondary)", fontWeight: 600 }}>{p.age} YRS | {p.gender.toUpperCase()}</p>
                      </div>
                      <span className="status-badge" style={{ alignSelf: "flex-start" }}>ID: {p.patient_id}</span>
                   </div>
                ))}
             </div>
           </div>
        )}

        {activeTab === "appointments" && (
           <div className="solid-card">
             <h2 className="form-header">
                <Calendar size={24} strokeWidth={3} /> SLOT ALLOCATION
             </h2>
             <form style={{ maxWidth: "480px" }} onSubmit={(e) => { e.preventDefault(); alert("ALLOCATION PENDING BACKEND INTEGRATION."); }}>
                <div className="input-group">
                   <label>PATIENT IDENTIFIER (PID)</label>
                   <input type="text" placeholder="E.G. 1" />
                </div>
                <div className="input-group">
                   <label>DOCTOR IDENTIFIER (DID)</label>
                   <input type="text" placeholder="E.G. 2" />
                </div>
                <div className="input-group">
                   <label>SCHEDULED TIMESTAMP</label>
                   <input type="datetime-local" />
                </div>
                <button type="submit" className="btn">CONFIRM ALLOCATION</button>
             </form>
           </div>
        )}

        {(activeTab === "billing" || activeTab === "doctors") && (
           <div className="solid-card" style={{ textAlign: "center", padding: "80px 20px" }}>
             <Pill size={64} color="var(--text-secondary)" strokeWidth={2} style={{ margin: "0 auto 24px" }} />
             <h2 style={{ fontSize: "2rem", textTransform: "uppercase", fontWeight: 800 }}>MODULE OFFLINE</h2>
             <p style={{ color: "var(--text-secondary)", marginTop: "12px", fontWeight: 600, letterSpacing: "1px" }}>THIS COMPONENT IS PENDING STRUCTURAL UPGRADES. ACCESS DENIED.</p>
           </div>
        )}
      </main>
    </div>
  );
}

export default App;
